def decide(reg: dict) -> str:
    for meta in reg.values():
        if not meta.get("owner"):
            return "ESCALATE_NO_OWNER"
        if meta.get("breaking") and meta.get("bump") != "major":
            return "REJECT_BUMP_POLICY"
    return "CONTINUE"

